  ('dietitian-moex-10704', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '葉酸與下列何種代謝反應無關？', '["嘌呤合成", "肝醣合成", "嘧啶合成", "胺基酸之互變"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "c3969470800c", "answer_pdf_sha1": "a5c2b584234f", "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10705', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '年第一次專門職業及技術人員高等暨普通考試醫事人員、 全一張 （正面） 中醫師、心理師、呼吸治療師、營養師、獸醫人員考試試題 等    別 ：高等考試 類    科 ：營養師 科    目 ：生理學與生物化學 甲、申論題部分：請以藍、黑色鋼筆或原子筆在申論試卷上橫式作答，於本試題上作答者，不予計分。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 94, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10706', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '人體由上皮、結締、肌肉和神經四大類組織所形成，下列何者最正確？ 神經組織大部分由神經元細胞組成，負責神經系統營養、支持、調節和傳導的功能 肌肉組織中的平滑肌和心肌皆無條紋，其收縮皆由自主神經系統控制 皮膚的真皮層由結締組織形成，其中含有膠原纖維蛋白可支撐疏鬆的組織結構 呼吸道由具有纖毛的單層上皮組織形成，可提供人體有效的保護', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10707', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '帕金森氏症（Parkinson’s disease）的病因為何？ 由於膽鹼性神經元（Cholinergic neuron）退化所致  由於肉毒桿菌毒素（Botulinum toxin）中毒所致 由於血清胺（Serotonin）代謝異常所致  由於黑質（Substantia nigra）受損所致', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10708', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '自主神經系統之交感神經活化所引起的反應包括那些？ 支氣管收縮  腸胃道運動受到抑制  胰臟的外分泌受到刺激  心跳速率減慢', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10709', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '代謝性酸中毒所引起的血液酸鹼度變化，會產生什麼現象？ 會引起代償性的換氣過度（Hyperventilation）  會引起代償性的換氣不足（Hypoventilation） 代償結果會引起續發性的呼吸性酸中毒  代償結果會造成血液中的二氧化碳增加', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10710', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者是先天免疫扮演人體防禦系統的第一道防線？ 淋巴激素的釋放  殺手T細胞的活化  淋巴球產生的抗體  白血球的吞噬作用', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10711', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '腎臟處理血液中各種物質的方式都不一樣，下列何者描述正確？ 蛋白質無法過濾，腎清除率為零 尿素可過濾且不會被再吸收或分泌，腎清除率等於腎絲球過濾率 葡萄糖可過濾及分泌，腎清除率大於腎絲球過濾率 鉀離子可過濾及部分再吸收，腎清除率小於腎絲球過濾率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10712', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關血液的組成，下列敘述何者正確？ 血漿為不含血球的部分，占45%以下  血清和血漿的成分一致，但多了纖維蛋白原 血液中的球蛋白除了產生抗體也幫助水溶性維生素的運送  血液中的白蛋白是最主要的蛋白質，可維持血液的滲透壓', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10713', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關血管的功能，下列敘述何者正確？ 彈性動脈（Artery）主要調節各器官的相對血流  肌性小動脈（Arteriole）是決定平均動脈壓的主要因子 微血管（Capillary）負責將血液帶回心臟  靜脈（Vein）提供營養素和代謝產物交換的場所', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
